  1→package provider
  2→
  3→import (
  4→	"bytes"
  5→	"context"
  6→	"encoding/json"
  7→	"fmt"
  8→	"io"
  9→	"net/http"
 10→	"time"
 11→)
 12→
 13→// Embedder generates vector embeddings from text.
 14→type Embedder interface {
 15→	Embed(ctx context.Context, text string) ([]float32, error)
 16→	Dimensions() int
 17→}
 18→
 19→const (
 20→	openAIEmbeddingURL    = "https://api.openai.com/v1/embeddings"
 21→	openAIEmbeddingModel  = "text-embedding-3-small"
 22→	embeddingDimensions   = 1536
 23→	embeddingTimeout      = 30 * time.Second
 24→	maxEmbeddingInputLen  = 30000 // rough char limit to stay under 8191 tokens
 25→)
 26→
 27→// OpenAIEmbedder generates embeddings via the OpenAI API.
 28→type OpenAIEmbedder struct {
 29→	apiKey string
 30→	model  string
 31→	client *http.Client
 32→}
 33→
 34→// OpenAIEmbedderOption configures an OpenAIEmbedder.
 35→type OpenAIEmbedderOption func(*OpenAIEmbedder)
 36→
 37→// WithEmbeddingModel sets a custom model name.
 38→func WithEmbeddingModel(model string) OpenAIEmbedderOption {
 39→	return func(e *OpenAIEmbedder) { e.model = model }
 40→}
 41→
 42→// WithEmbeddingHTTPClient sets a custom HTTP client (useful for testing).
 43→func WithEmbeddingHTTPClient(c *http.Client) OpenAIEmbedderOption {
 44→	return func(e *OpenAIEmbedder) { e.client = c }
 45→}
 46→
 47→// NewOpenAIEmbedder creates an OpenAI-based embedder.
 48→func NewOpenAIEmbedder(apiKey string, opts ...OpenAIEmbedderOption) *OpenAIEmbedder {
 49→	e := &OpenAIEmbedder{
 50→		apiKey: apiKey,
 51→		model:  openAIEmbeddingModel,
 52→		client: &http.Client{Timeout: embeddingTimeout},
 53→	}
 54→	for _, opt := range opts {
 55→		opt(e)
 56→	}
 57→	return e
 58→}
 59→
 60→// Dimensions returns the embedding vector size.
 61→func (e *OpenAIEmbedder) Dimensions() int { return embeddingDimensions }
 62→
 63→type embeddingRequest struct {
 64→	Input string `json:"input"`
 65→	Model string `json:"model"`
 66→}
 67→
 68→type embeddingResponse struct {
 69→	Data []struct {
 70→		Embedding []float32 `json:"embedding"`
 71→	} `json:"data"`
 72→	Error *struct {
 73→		Message string `json:"message"`
 74→	} `json:"error"`
 75→}
 76→
 77→// Embed generates a vector embedding for the given text.
 78→func (e *OpenAIEmbedder) Embed(ctx context.Context, text string) ([]float32, error) {
 79→	if text == "" {
 80→		return nil, fmt.Errorf("provider: embed: empty input")
 81→	}
 82→
 83→	// Truncate to avoid token limit errors
 84→	if len(text) > maxEmbeddingInputLen {
 85→		text = text[:maxEmbeddingInputLen]
 86→	}
 87→
 88→	body, err := json.Marshal(embeddingRequest{
 89→		Input: text,
 90→		Model: e.model,
 91→	})
 92→	if err != nil {
 93→		return nil, fmt.Errorf("provider: embed: marshal request: %w", err)
 94→	}
 95→
 96→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, openAIEmbeddingURL, bytes.NewReader(body))
 97→	if err != nil {
 98→		return nil, fmt.Errorf("provider: embed: build request: %w", err)
 99→	}
100→	req.Header.Set("Content-Type", "application/json")
101→	req.Header.Set("Authorization", "Bearer "+e.apiKey)
102→
103→	resp, err := e.client.Do(req)
104→	if err != nil {
105→		return nil, fmt.Errorf("provider: embed: http: %w", err)
106→	}
107→	defer func() { _ = resp.Body.Close() }()
108→
109→	respBody, err := io.ReadAll(resp.Body)
110→	if err != nil {
111→		return nil, fmt.Errorf("provider: embed: read response: %w", err)
112→	}
113→
114→	if resp.StatusCode != http.StatusOK {
115→		return nil, fmt.Errorf("provider: embed: api status %d: %s", resp.StatusCode, string(respBody))
116→	}
117→
118→	var result embeddingResponse
119→	if err := json.Unmarshal(respBody, &result); err != nil {
120→		return nil, fmt.Errorf("provider: embed: unmarshal response: %w", err)
121→	}
122→
123→	if result.Error != nil {
124→		return nil, fmt.Errorf("provider: embed: api error: %s", result.Error.Message)
125→	}
126→
127→	if len(result.Data) == 0 || len(result.Data[0].Embedding) == 0 {
128→		return nil, fmt.Errorf("provider: embed: empty embedding in response")
129→	}
130→
131→	return result.Data[0].Embedding, nil
132→}
