377→// ContentUpdate holds fields that background workers set after processing an item.
378→type ContentUpdate struct {
379→	Status      string
380→	Title       *string
381→	ContentText *string
382→	ContentURL  *string
383→}
384→
385→// UpdateContent updates worker-managed fields (status, title, content) on an item.
386→// This is used by background jobs, not exposed via GraphQL.
387→func (s *Service) UpdateContent(ctx context.Context, itemID uuid.UUID, input ContentUpdate) error {
388→	sets := []string{fmt.Sprintf("status = $%d", 2)}
389→	args := []any{itemID, input.Status}
390→	paramIdx := 3
391→
392→	if input.Title != nil {
393→		sets = append(sets, fmt.Sprintf("title = $%d", paramIdx))
394→		args = append(args, *input.Title)
395→		paramIdx++
396→	}
397→	if input.ContentText != nil {
398→		sets = append(sets, fmt.Sprintf("content_text = $%d", paramIdx))
399→		args = append(args, *input.ContentText)
400→		paramIdx++
401→	}
402→	if input.ContentURL != nil {
403→		sets = append(sets, fmt.Sprintf("content_url = $%d", paramIdx))
404→		args = append(args, *input.ContentURL)
405→		paramIdx++ //nolint:ineffassign // keeps pattern consistent for future fields
406→	}
407→
408→	query := fmt.Sprintf(`UPDATE items SET %s WHERE id = $1`, joinSets(sets))
409→	tag, err := s.pool.Exec(ctx, query, args...)
410→	if err != nil {
411→		return fmt.Errorf("item: update content: %w", err)
412→	}
413→	if tag.RowsAffected() == 0 {
414→		return fmt.Errorf("item: update content: not found")
415→	}
416→	return nil
417→}
418→
419→func joinSets(sets []string) string {
420→	result := ""
421→	for i, s := range sets {
422→		if i > 0 {
423→			result += ", "
424→		}
425→		result += s
426→	}
427→	return result
428→}
