 41→	Result
 42→	Content []Content `json:"content"` // Can be TextContent, ImageContent, AudioContent, or EmbeddedResource
 43→	// Structured content returned as a JSON object in the structuredContent field of a result.
 44→	// For backwards compatibility, a tool that returns structured content SHOULD also return
 45→	// functionally equivalent unstructured content.
