 83→// This is useful for working with strongly-typed arguments
 84→func (r CallToolRequest) BindArguments(target any) error {
 85→	if target == nil || reflect.ValueOf(target).Kind() != reflect.Ptr {
 86→		return fmt.Errorf("target must be a non-nil pointer")
 87→	}
 88→
 89→	// Fast-path: already raw JSON
 90→	if raw, ok := r.Params.Arguments.(json.RawMessage); ok {
 91→		return json.Unmarshal(raw, target)
 92→	}
 93→
 94→	data, err := json.Marshal(r.Params.Arguments)
 95→	if err != nil {
 96→		return fmt.Errorf("failed to marshal arguments: %w", err)
 97→	}
 98→
