160→// StreamableHTTPServer implements a Streamable-http based MCP server.
161→// It communicates with clients over HTTP protocol, supporting both direct HTTP responses, and SSE streams.
162→// https://modelcontextprotocol.io/specification/2025-03-26/basic/transports#streamable-http
163→//
164→// Usage:
165→//
166→//	server := NewStreamableHTTPServer(mcpServer)
167→//	server.Start(":8080") // The final url for client is http://xxxx:8080/mcp by default
168→//
169→// or the server itself can be used as a http.Handler, which is convenient to
170→// integrate with existing http servers, or advanced usage:
171→//
172→//	handler := NewStreamableHTTPServer(mcpServer)
173→//	http.Handle("/streamable-http", handler)
174→//	http.ListenAndServe(":8080", nil)
175→//
176→// Notice:
177→// Except for the GET handlers(listening), the POST handlers(request/notification) will
178→// not trigger the session registration. So the methods like `SendNotificationToSpecificClient`
179→// or `hooks.onRegisterSession` will not be triggered for POST messages.
180→//
181→// The current implementation does not support the following features from the specification:
182→//   - Stream Resumability
183→type StreamableHTTPServer struct {
184→	server                   *MCPServer
185→	sessionTools             *sessionToolsStore
186→	sessionResources         *sessionResourcesStore
187→	sessionResourceTemplates *sessionResourceTemplatesStore
188→	sessionRequestIDs        sync.Map // sessionId --> last requestID(*atomic.Int64)
189→	activeSessions           sync.Map // sessionId --> *streamableHttpSession (for sampling responses)
190→
191→	httpServer *http.Server
192→	mu         sync.RWMutex
193→
194→	endpointPath             string
195→	contextFunc              HTTPContextFunc
196→	sessionIdManagerResolver SessionIdManagerResolver
197→	sessionIdManager         SessionIdManager // for non-request contexts (sweeper)
198→	listenHeartbeatInterval  time.Duration
199→	logger                   util.Logger
200→	sessionLogLevels         *sessionLogLevelsStore
201→	disableStreaming         bool
202→
203→	tlsCertFile string
204→	tlsKeyFile  string
205→
206→	sessionIdleTTL    time.Duration
207→	sessionLastActive sync.Map // sessionID → *atomic.Int64 (unix nanos)
208→	sweeperCancel     context.CancelFunc
209→}
