211→// NewStreamableHTTPServer creates a new streamable-http server instance
212→func NewStreamableHTTPServer(server *MCPServer, opts ...StreamableHTTPOption) *StreamableHTTPServer {
213→	s := &StreamableHTTPServer{
214→		server:                   server,
215→		sessionTools:             newSessionToolsStore(),
216→		sessionLogLevels:         newSessionLogLevelsStore(),
217→		endpointPath:             "/mcp",
218→		sessionIdManagerResolver: NewDefaultSessionIdManagerResolver(&StatelessGeneratingSessionIdManager{}),
219→		logger:                   util.DefaultLogger(),
220→		sessionResources:         newSessionResourcesStore(),
221→		sessionResourceTemplates: newSessionResourceTemplatesStore(),
222→	}
223→
224→	// Apply all options
225→	for _, opt := range opts {
226→		opt(s)
227→	}
228→
229→	// Cache the session ID manager for use in non-request contexts (sweeper).
230→	// DefaultSessionIdManagerResolver always returns the same manager,
231→	// so resolving it once at startup is semantically identical.
232→	if r, ok := s.sessionIdManagerResolver.(*DefaultSessionIdManagerResolver); ok {
233→		s.sessionIdManager = r.manager
234→	}
235→
236→	if s.sessionIdleTTL > 0 {
237→		ctx, cancel := context.WithCancel(context.Background())
238→		s.sweeperCancel = cancel
239→		s.startSessionSweeper(ctx)
240→	}
241→
242→	return s
243→}
