245→// ServeHTTP implements the http.Handler interface.
246→func (s *StreamableHTTPServer) ServeHTTP(w http.ResponseWriter, r *http.Request) {
247→	switch r.Method {
248→	case http.MethodPost:
249→		s.handlePost(w, r)
250→	case http.MethodGet:
251→		s.handleGet(w, r)
252→	case http.MethodDelete:
253→		s.handleDelete(w, r)
254→	default:
255→		http.NotFound(w, r)
256→	}
257→}
