259→// Start begins serving the http server on the specified address and path
260→// (endpointPath). like:
261→//
262→//	s.Start(":8080")
263→func (s *StreamableHTTPServer) Start(addr string) error {
264→	s.mu.Lock()
265→	if s.httpServer == nil {
266→		mux := http.NewServeMux()
267→		mux.Handle(s.endpointPath, s)
268→		s.httpServer = &http.Server{
269→			Addr:    addr,
270→			Handler: mux,
271→		}
272→	} else {
273→		if s.httpServer.Addr == "" {
274→			s.httpServer.Addr = addr
