package version

// Version and BuildTime are set at build time via ldflags.
var (
	Version   = "dev"
	BuildTime = "unknown"
)

package auth

import "context"

type contextKey struct{}

// WithClaims stores JWT claims in the context.
func WithClaims(ctx context.Context, claims *Claims) context.Context {
	return context.WithValue(ctx, contextKey{}, claims)
}

// GetClaims retrieves JWT claims from the context. Returns nil if not present.
func GetClaims(ctx context.Context) *Claims {
	claims, _ := ctx.Value(contextKey{}).(*Claims)
	return claims
}

package item

import (
	"time"

	"github.com/google/uuid"
)

// Item represents an item stored in the database.
type Item struct {
	ID           uuid.UUID
	OwnerID      uuid.UUID
	Type         string
	Status       string
	Sensitivity  string
	Title        *string
	ContentText  *string
	ContentURL   *string
	Tags         []string
	Metadata     map[string]any
	AutoMetadata map[string]any
	Source       string
	SourceURL    *string
	CreatedAt    time.Time
	UpdatedAt    time.Time
	CapturedAt   time.Time
}

// SearchResult holds a page of items with total count.
type SearchResult struct {
	Items   []*Item
	Total   int
	HasMore bool
}

// Filter describes optional filters for listing items.
type Filter struct {
	Types       []string
	Tags        []string
	Sensitivity []string
	Source      *string
	DateFrom   *time.Time
	DateTo     *time.Time
	Status     []string
}

// Sort describes ordering for item listings.
type Sort struct {
	Field     string
	Direction string
}

// BookmarkInput holds parameters for creating a bookmark item.
type BookmarkInput struct {
	URL         string
	Title       *string
	Selection   *string
	Referrer    *string
	Tags        []string
	Sensitivity string
	Source      string
}

// NoteInput holds parameters for creating a text note item.
type NoteInput struct {
	Title       *string
	Content     string
	Tags        []string
	Sensitivity string
	Source      string
}

// VoiceNoteInput holds parameters for creating a voice note item.
type VoiceNoteInput struct {
	AudioKey    string
	Title       *string
	Tags        []string
	Sensitivity string
	Source      string
}

// UpdateInput holds optional fields for updating an item.
type UpdateInput struct {
	Title       *string
	Tags        []string
	Sensitivity *string
}

