		t.Error("expected markdown heading with title")
	}
	if !strings.Contains(result, "bookmark") {
		t.Error("expected item type")
	}
	if !strings.Contains(result, "Some content here") {
		t.Error("expected content")
	}
	if !strings.Contains(result, "test, example") {
		t.Error("expected tags")
	}
