func assertResultContains(t *testing.T, result *mcpgo.CallToolResult, expected string) {
	t.Helper()
	for _, c := range result.Content {
		if tc, ok := c.(mcpgo.TextContent); ok {
			if strings.Contains(tc.Text, expected) {
				return
			}
		}
	}
	t.Errorf("expected result to contain %q", expected)
}

