package mcp

import (
	"context"
	"errors"
	"strings"
	"testing"
	"time"

	"github.com/google/uuid"
	mcpgo "github.com/mark3labs/mcp-go/mcp"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/item"
)

// --- mocks ---

type mockItemSearcher struct {
	getByIDFn         func(ctx context.Context, ownerID, itemID uuid.UUID) (*item.Item, error)
	searchFn          func(ctx context.Context, ownerID uuid.UUID, query string, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error)
	semanticSearchFn  func(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error)
	captureBookmarkFn func(ctx context.Context, ownerID uuid.UUID, input item.BookmarkInput) (*item.Item, error)
	captureNoteFn     func(ctx context.Context, ownerID uuid.UUID, input item.NoteInput) (*item.Item, error)
}

func (m *mockItemSearcher) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*item.Item, error) {
	return m.getByIDFn(ctx, ownerID, itemID)
}
func (m *mockItemSearcher) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error) {
	return m.searchFn(ctx, ownerID, query, filter, limit, threshold)
}
func (m *mockItemSearcher) SemanticSearch(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error) {
	return m.semanticSearchFn(ctx, ownerID, embedding, filter, limit, threshold)
}
func (m *mockItemSearcher) CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input item.BookmarkInput) (*item.Item, error) {
	return m.captureBookmarkFn(ctx, ownerID, input)
}
func (m *mockItemSearcher) CaptureNote(ctx context.Context, ownerID uuid.UUID, input item.NoteInput) (*item.Item, error) {
	return m.captureNoteFn(ctx, ownerID, input)
}

type mockEmbedder struct {
	embedFn func(ctx context.Context, text string) ([]float32, error)
	dims    int
}

func (m *mockEmbedder) Embed(ctx context.Context, text string) ([]float32, error) {
	return m.embedFn(ctx, text)
}
func (m *mockEmbedder) Dimensions() int { return m.dims }

// --- helpers ---

func testClaims() *auth.Claims {
	return &auth.Claims{
		UserID: uuid.MustParse("11111111-1111-1111-1111-111111111111"),
		Email:  "test@example.com",
	}
}

func authedCtx() context.Context {
	return auth.WithClaims(context.Background(), testClaims())
}

func testItem() *item.Item {
	title := "Test Item"
	content := "Some content here"
	return &item.Item{
		ID:          uuid.MustParse("22222222-2222-2222-2222-222222222222"),
		OwnerID:     uuid.MustParse("11111111-1111-1111-1111-111111111111"),
		Type:        "bookmark",
		Status:      "ready",
		Sensitivity: "normal",
		Title:       &title,
		ContentText: &content,
		Tags:        []string{"test", "example"},
		Source:      "mcp",
		CreatedAt:   time.Date(2026, 3, 10, 0, 0, 0, 0, time.UTC),
		UpdatedAt:   time.Date(2026, 3, 10, 0, 0, 0, 0, time.UTC),
		CapturedAt:  time.Date(2026, 3, 10, 0, 0, 0, 0, time.UTC),
	}
}

func makeCallToolRequest(name string, args map[string]any) mcpgo.CallToolRequest {
	return mcpgo.CallToolRequest{
		Params: mcpgo.CallToolParams{
			Name:      name,
			Arguments: args,
		},
	}
}

func searchResult(items ...*item.Item) *item.SearchResult {
	return &item.SearchResult{
		Items:   items,
		Total:   len(items),
		HasMore: false,
	}
}

// --- search handler tests ---

func TestSearchHandler_SemanticSearch(t *testing.T) {
	it := testItem()
	deps := Deps{
		Items: &mockItemSearcher{
			semanticSearchFn: func(_ context.Context, _ uuid.UUID, _ []float32, _ *item.Filter, _ int, _ float64) (*item.SearchResult, error) {
				return searchResult(it), nil
			},
		},
		Embedder: &mockEmbedder{
			embedFn: func(_ context.Context, _ string) ([]float32, error) {
				return []float32{0.1, 0.2}, nil
			},
			dims: 2,
		},
	}

	handler := searchHandler(deps)
	req := makeCallToolRequest("search", map[string]any{"query": "test query"})
	result, err := handler(authedCtx(), req)

	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result.IsError {
		t.Fatal("expected success result")
	}
	assertResultContains(t, result, "Test Item")
}

